namespace SpriteKind {
    export const Player1 = SpriteKind.create()
    export const Player2 = SpriteKind.create()
    export const Ball2 = SpriteKind.create()
    export const Ball1 = SpriteKind.create()
}
namespace StatusBarKind {
    export const Meter1 = StatusBarKind.create()
    export const Meter2 = StatusBarKind.create()
}
sprites.onOverlap(SpriteKind.Ball1, SpriteKind.Player2, function (sprite, otherSprite) {
    Ball_PlayerVelocity = otherSprite.vx
    Ball_PlayerAcceleration = otherSprite.ax
    if (Ball_PlayerVelocity < 0) {
        sprite.x = otherSprite.x - 7
        extraEffects.createSpreadEffectAt(Effect_FlashLeft, otherSprite.x - 7, sprite.y, Ball_PlayerVelocity / -6, Ball_PlayerVelocity / -3, Ball_PlayerVelocity / -5)
        extraEffects.createSpreadEffectAt(Effect_FlashMiddle, otherSprite.x - 7, sprite.y, Ball_PlayerVelocity / -6, Ball_PlayerVelocity / -3, Ball_PlayerVelocity / -5)
    }
    sprite.setKind(SpriteKind.Ball2)
    otherSprite.vx = 0
    otherSprite.ax = 0
    sprite.setVelocity(0, 0)
    scene.cameraShake(Math.max(0, Ball_PlayerVelocity * -1 / 30), Math.max(0, Ball_PlayerVelocity * -1 * 1.1))
    Ball_VFX = sprites.create(img`
        . . . . . . . . . . . 7 d . 7 . 
        . . . . . . . . . . . . 7 d 6 d 
        . . . . . . . . . . . . 6 7 d 7 
        . . . . . . . . . . . . d 7 7 6 
        . . . . . . . . . . . . . 6 7 6 
        . . . . . . . . . . . . . d 6 7 
        . . . . . . . . . . . . . 7 d 6 
        . . . . . . . . . . . . . . 7 6 
        . . . . . . . . . . . . . . 6 6 
        . . . . . . . . . . . . . 7 d 6 
        . . . . . . . . . . . . . d 6 7 
        . . . . . . . . . . . . . 6 7 6 
        . . . . . . . . . . . . d 7 7 6 
        . . . . . . . . . . . . 6 7 d 7 
        . . . . . . . . . . . . 7 d 6 d 
        . . . . . . . . . . . 7 d . 7 . 
        `, SpriteKind.Player)
    animation.runImageAnimation(
    Ball_VFX,
    [img`
        . . . . . . . . . . . 7 d . 7 . 
        . . . . . . . . . . . . 7 d 6 d 
        . . . . . . . . . . . . 6 7 d 7 
        . . . . . . . . . . . . d 7 7 6 
        . . . . . . . . . . . . . 6 7 6 
        . . . . . . . . . . . . . d 6 7 
        . . . . . . . . . . . . . 7 d 6 
        . . . . . . . . . . . . . . 7 7 
        . . . . . . . . . . . . . . 7 6 
        . . . . . . . . . . . . . 7 d 6 
        . . . . . . . . . . . . . d 6 7 
        . . . . . . . . . . . . . 6 7 6 
        . . . . . . . . . . . . d 7 7 6 
        . . . . . . . . . . . . 6 7 d 7 
        . . . . . . . . . . . . 7 d 6 d 
        . . . . . . . . . . . 7 d . 7 . 
        `,img`
        . . . . . . . . . . . 7 d . 7 . 
        . . . . . . . . . . . . 7 d 4 d 
        . . . . . . . . . . . . 4 7 d 7 
        . . . . . . . . . . . . d 7 7 4 
        . . . . . . . . . . . . . 4 7 4 
        . . . . . . . . . . . . . d 4 7 
        . . . . . . . . . . . . . 7 d 4 
        . . . . . . . . . . . . . . 7 7 
        . . . . . . . . . . . . . . 7 4 
        . . . . . . . . . . . . . 7 d 4 
        . . . . . . . . . . . . . d 4 7 
        . . . . . . . . . . . . . 4 7 4 
        . . . . . . . . . . . . d 7 7 4 
        . . . . . . . . . . . . 4 7 d 7 
        . . . . . . . . . . . . 7 d 4 d 
        . . . . . . . . . . . 7 d . 7 . 
        `],
    100,
    true
    )
    Ball_VFX.setPosition(otherSprite.x - 11, sprite.y)
    animation.runImageAnimation(
    sprite,
    [img`
        . 1 4 4 4 4 1 . 
        1 4 7 7 7 7 4 1 
        4 7 7 7 7 7 7 4 
        4 7 7 7 7 7 7 4 
        4 7 7 7 7 7 7 4 
        4 7 7 7 7 7 7 4 
        1 4 7 7 7 7 4 1 
        . 1 4 4 4 4 1 . 
        `,img`
        . 2 d d d d 2 . 
        2 d 3 3 3 3 d 2 
        d 3 3 3 7 7 3 d 
        d 3 3 3 3 7 3 d 
        d 3 3 3 3 3 3 d 
        d 4 3 3 3 3 3 d 
        2 d 4 3 3 4 d 2 
        . 2 d d d d 2 . 
        `],
    100,
    true
    )
    PlayFlash(Ball_PlayerVelocity * -1, Ball_PlayerVelocity * -1.1)
    timer.after(Math.max(0, Ball_PlayerVelocity * -1.5), function () {
        sprites.destroy(Ball_VFX)
        otherSprite.x += 1
        otherSprite.vx = Ball_PlayerVelocity + 3
        otherSprite.ax = Ball_PlayerAcceleration
        sprite.vx = Game_BallSpeed * -0.5 * Game_GameSpeed + Math.min(0, otherSprite.vx / 3)
        if (sprite.y < otherSprite.y) {
            sprite.vy = Game_BallSpeed * -1 * Game_GameSpeed + Math.min(0, otherSprite.vx / 4)
        } else {
            sprite.vy = Game_BallSpeed * 1 * Game_GameSpeed - Math.min(0, otherSprite.vx / 4)
        }
        PlayBounce()
        Game_GameSpeed += 0.1
        if (Ball_PlayerVelocity >= 0) {
            animation.runImageAnimation(
            sprite,
            [img`
                . 1 4 4 4 4 1 . 
                1 4 7 7 7 7 4 1 
                4 7 7 7 7 7 7 4 
                4 7 7 7 7 7 7 4 
                4 7 7 7 7 7 7 4 
                4 7 7 7 7 7 7 4 
                1 4 7 7 7 7 4 1 
                . 1 4 4 4 4 1 . 
                `,img`
                . 2 d d d d 2 . 
                2 d 3 3 3 3 d 2 
                d 3 3 3 7 7 3 d 
                d 3 3 3 3 7 3 d 
                d 3 3 3 3 3 3 d 
                d 4 3 3 3 3 3 d 
                2 d 4 3 3 4 d 2 
                . 2 d d d d 2 . 
                `],
            200,
            false
            )
        }
    })
})
