function PlayFlash (Velocity: number, Length: number) {
    music.play(music.createSoundEffect(
    WaveShape.Square,
    20 * Velocity,
    30 * Velocity,
    255,
    0,
    Length,
    SoundExpressionEffect.None,
    InterpolationCurve.Linear
    ), music.PlaybackMode.UntilDone)
}
function SetMeters () {
    sprites.destroyAllSpritesOfKind(SpriteKind.StatusBar)
    Game_Player1ChargeMeter = statusbars.create(50, 5, StatusBarKind.Meter1)
    Game_Player1ChargeMeter.setStatusBarFlag(StatusBarFlag.SmoothTransition, false)
    Game_Player1ChargeMeter.value = 0
    Game_Player1ChargeMeter.setBarBorder(1, 7)
    Game_Player1ChargeMeter.setColor(5, 13, 1)
    tiles.placeOnTile(Game_Player1ChargeMeter, tiles.getTileLocation(2, 0))
    Game_Player1ChargeMeter.x += -8
    Game_Player1ChargeMeter.y += 5
    Game_Player2ChargeMeter = statusbars.create(50, 5, StatusBarKind.Meter2)
    Game_Player2ChargeMeter.setStatusBarFlag(StatusBarFlag.SmoothTransition, false)
    Game_Player2ChargeMeter.value = 100
    Game_Player2ChargeMeter.setBarBorder(1, 7)
    Game_Player2ChargeMeter.setColor(13, 5, 1)
    tiles.placeOnTile(Game_Player2ChargeMeter, tiles.getTileLocation(7, 0))
    Game_Player2ChargeMeter.x += 8
    Game_Player2ChargeMeter.y += 5
}
