controller.up.onEvent(ControllerButtonEvent.Pressed, function () {
    timer.after(10, function () {
        if (controller.down.isPressed() && Title_isGameReadyToStart) {
            StartGame()
        } else if (controller.down.isPressed() && Game_isPlayer1Ready) {
            Player1Charge()
        } else if (Game_isPlayer1Ready) {
            Player1Up()
        }
    })
})
