scene.onHitWall(SpriteKind.Ball2, function (sprite, location) {
    PlayBump()
    if (sprite.isHittingTile(CollisionDirection.Left)) {
        sprite.setKind(SpriteKind.Player)
        sprite.setVelocity(0, 0)
        sprite.x = 4
        Player2Point()
    }
})
