function SetRound (P1chance: number) {
    Game_GameSpeed = 1
    Game_BallSpeed = 50
    SetPlayers()
    SetMeters()
    Game_isPlaying = true
    if (Math.percentChance(P1chance)) {
        SetPlayer1Serve()
    } else {
        SetPlayer2Serve()
    }
}
controller.left.onEvent(ControllerButtonEvent.Pressed, function () {
	
})
function CreateMenu () {
    Title_Menu = miniMenu.createMenu(
    miniMenu.createMenuItem("Start"),
    miniMenu.createMenuItem("Quit")
    )
    Title_Menu.setStyleProperty(miniMenu.StyleKind.DefaultAndSelected, miniMenu.StyleProperty.Padding, 1)
    Title_Menu.setStyleProperty(miniMenu.StyleKind.DefaultAndSelected, miniMenu.StyleProperty.Border, 1)
    Title_Menu.setStyleProperty(miniMenu.StyleKind.Selected, miniMenu.StyleProperty.BorderColor, 4)
    Title_Menu.setStyleProperty(miniMenu.StyleKind.Default, miniMenu.StyleProperty.BorderColor, 13)
    Title_Menu.setStyleProperty(miniMenu.StyleKind.Default, miniMenu.StyleProperty.Background, 13)
    Title_Menu.setStyleProperty(miniMenu.StyleKind.Selected, miniMenu.StyleProperty.Background, 13)
    Title_Menu.setStyleProperty(miniMenu.StyleKind.Default, miniMenu.StyleProperty.Foreground, 5)
    Title_Menu.setStyleProperty(miniMenu.StyleKind.Selected, miniMenu.StyleProperty.Foreground, 7)
    Title_Menu.y += 40
    Title_Menu.x += -1
    Title_Menu.onButtonPressed(controller.A, function (selection, selectedIndex) {
        if (selection == "Start") {
            StartGame()
            Title_Menu.close()
        } else {
            Title_Menu.close()
            game.setGameOverMessage(false, "Thanks for playing!")
            game.setGameOverPlayable(false, music.melodyPlayable(music.baDing), false)
            game.setGameOverEffect(false, color.RotatePalette)
            game.gameOver(false)
        }
    })
}
