    Player2Stop()
    Game_isPlayer2Ready = false
    Game_isPlayer1Ready = false
    music.setVolume(100)
    music.play(music.melodyPlayable(music.baDing), music.PlaybackMode.InBackground)
    music.setVolume(255)
    timer.after(500, function () {
        Game_Player1Score += 1
        UpdateScore()
        timer.after(1500, function () {
            if (Game_Player1Score >= 5) {
                Player1Win()
            } else {
                SetRound(100)
            }
        })
    })
