function ReadyPlayers () {
    Game_isPlayer2Ready = true
    Game_isPlayer1Ready = true
    Game_isPlaying = true
}
function Player2ServeUp () {
    Game_isPlayer2Serving = false
    sprites.destroy(Game_BallArrow)
    Game_Ball.setVelocity(Game_BallSpeed * -0.5 * (Game_GameSpeed * 1.5), Game_BallSpeed * -1 * (Game_GameSpeed * 1.5))
    PlayServe()
}
function SetPlayers () {
    sprites.destroyAllSpritesOfKind(SpriteKind.Player)
    sprites.destroyAllSpritesOfKind(SpriteKind.Player1)
    sprites.destroyAllSpritesOfKind(SpriteKind.Player2)
    Game_Player1 = sprites.create(assets.image`Player1`, SpriteKind.Player1)
    tiles.placeOnTile(Game_Player1, tiles.getTileLocation(0, 3))
    Game_Player1.y += 8
    Game_isPlayer1Serving = false
    Game_isPlayer1Charging = false
    Game_isPlayer1Ready = false
    Game_Player2 = sprites.create(assets.image`Player2`, SpriteKind.Player2)
    tiles.placeOnTile(Game_Player2, tiles.getTileLocation(9, 3))
    Game_Player2.y += 8
    Game_isPlayer2Serving = false
    Game_isPlayer2Charging = false
    Game_isPlayer2Ready = false
}
function PlayBump () {
    music.play(music.createSoundEffect(WaveShape.Sine, 288, 63, 255, 0, 150, SoundExpressionEffect.None, InterpolationCurve.Linear), music.PlaybackMode.InBackground)
}
