statusbars.onStatusReached(StatusBarKind.Meter1, statusbars.StatusComparison.GT, statusbars.ComparisonType.Percentage, 90, function (status) {
    Game_Player1ChargeMeter.setColor(3, 13)
    Game_Player1.startEffect(effects.trail)
    music.play(music.createSoundEffect(WaveShape.Triangle, 4387, 5000, 99, 0, 100, SoundExpressionEffect.None, InterpolationCurve.Logarithmic), music.PlaybackMode.UntilDone)
})
statusbars.onStatusReached(StatusBarKind.Meter1, statusbars.StatusComparison.GT, statusbars.ComparisonType.Percentage, 10, function (status) {
    Game_Player1ChargeMeter.setColor(2, 13)
    music.play(music.createSoundEffect(WaveShape.Triangle, 1980, 2247, 99, 0, 100, SoundExpressionEffect.None, InterpolationCurve.Logarithmic), music.PlaybackMode.UntilDone)
})
function Player2ServeDown () {
    Game_isPlayer2Serving = false
    sprites.destroy(Game_BallArrow)
    Game_Ball.setVelocity(Game_BallSpeed * -0.5 * (Game_GameSpeed * 1.5), Game_BallSpeed * 1 * (Game_GameSpeed * 1.5))
    PlayServe()
}
controller.down.onEvent(ControllerButtonEvent.Pressed, function () {
    timer.after(10, function () {
        if (controller.up.isPressed() && Title_isGameReadyToStart) {
            StartGame()
        } else if (controller.up.isPressed() && Game_isPlayer1Ready) {
            Player1Charge()
        } else if (Game_isPlayer1Ready) {
            Player1Down()
        }
    })
})
controller.menu.onEvent(ControllerButtonEvent.Pressed, function () {
	
})
statusbars.onStatusReached(StatusBarKind.Meter2, statusbars.StatusComparison.LT, statusbars.ComparisonType.Percentage, 10, function (status) {
    Game_Player2ChargeMeter.setColor(13, 7)
    Game_Player2.startEffect(effects.trail)
    music.play(music.createSoundEffect(WaveShape.Triangle, 4387, 5000, 99, 0, 100, SoundExpressionEffect.None, InterpolationCurve.Logarithmic), music.PlaybackMode.UntilDone)
})
controller.B.onEvent(ControllerButtonEvent.Released, function () {
    if (Game_isPlayer2Charging) {
        Player2Release()
    } else if (Game_isPlayer2Ready) {
        Player2Stop()
    }
})
function Player1Release () {
    if (Game_Player1ChargeMeter.value < 10) {
        Game_Player1ChargeMeter.value = 0
        Game_isPlayer1Ready = true
        Game_isPlayer1Charging = false
        if (controller.up.isPressed()) {
            Player1Up()
        } else if (controller.down.isPressed()) {
            Player1Down()
        } else {
            Player1Stop()
        }
    } else {
        Game_isPlayer1Charging = false
        Game_Player1.ax = -1000 * Game_GameSpeed
        Game_Player1.vx = (Game_Player1ChargeMeter.value / 2 + 50) * 3 * Game_GameSpeed
        PlayJump()
    }
}
function UpdateChargeMeters () {
    if (Game_isPlayer1Charging) {
        Game_Player1ChargeMeter.value += 1 * Game_GameSpeed
    }
    if (Game_isPlayer2Charging) {
        Game_Player2ChargeMeter.value += -1 * Game_GameSpeed
    }
}
function PlayServe () {
    music.play(music.createSoundEffect(WaveShape.Triangle, 687, 3852, 170, 0, 150, SoundExpressionEffect.None, InterpolationCurve.Curve), music.PlaybackMode.InBackground)
    music.play(music.createSoundEffect(WaveShape.Triangle, 5000, 1, 170, 0, 150, SoundExpressionEffect.None, InterpolationCurve.Curve), music.PlaybackMode.InBackground)
}
