let Game_FirstTo5: Sprite = null
let Game_isPlayer1Ready = false
let Game_Player1: Sprite = null
let Game_isPlayer1ServeDown = false
let Game_BallArrow: Sprite = null
let Game_isPlayer1Serving = false
let Game_Player2ChargeMeter: StatusBarSprite = null
let Game_Player1ChargeMeter: StatusBarSprite = null
let Title_Title: Sprite = null
let Title_Players: Sprite = null
let Title_isGameReadyToStart = false
let Game_GameSpeed = 0
let Game_BallSpeed = 0
let Ball_VFX: Sprite = null
let Effect_FlashMiddle: SpreadEffectData = null
let Effect_FlashLeft: SpreadEffectData = null
let Ball_PlayerAcceleration = 0
let Ball_PlayerVelocity = 0
music.stopAllSounds()
music.setVolume(255)
CreateEffects()
Whiskyjack_Intro()
timer.after(5500, function () {
    Pong_Title_Screen()
})
game.onUpdate(function () {
    if (Game_isPlaying) {
        if (Game_isPlayer1Serving) {
            Game_Ball.setPosition(Game_Player1.x + 7, Game_Player1.y)
            Game_BallArrow.setPosition(Game_Player1.x + 11, Game_Player1.y)
        } else if (Game_isPlayer2Serving) {
            Game_Ball.setPosition(Game_Player2.x - 7, Game_Player2.y)
            Game_BallArrow.setPosition(Game_Player2.x - 11, Game_Player2.y)
        }
    }
})
game.onUpdateInterval(10, function () {
    UpdateChargeMeters()
})
